    "wizard_std_manual_add_btn": "Manually ongerako a urwego code ico wasn't found in the rondera.",
    "wizard_std_manual_input": "Injiza a urwego code manually (e.g., 'CCSS.ELA-LITERACY.RI.5.1').",
    "wizard_std_mode_ai": "Koresha AI to automatically identify relevant urwego from your ibirimwo.",
